import{_ as e,o as a,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"MMP Migration Guide","description":"","frontmatter":{"title":"MMP Migration Guide","slug":"mmp-migration-guide"},"headers":[],"relativePath":"marketer-hub/mmp-migration-guide.md","filePath":"marketer-hub/mmp-migration-guide.md"}'),o={name:"marketer-hub/mmp-migration-guide.md"};function i(s,t,d,h,l,p){return a(),r("div",null,[...t[0]||(t[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This guide walks you through how to migrate from your current MMP (Adjust, Singular, Kochava, Appsflyer, etc.) to Branch.</p><h2 id="best-practices" tabindex="-1">Best practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best practices&quot;">​</a></h2><p>To help ensure a seamless transition to Branch, we recommend implementing these best practices:</p><ul><li><strong>Start small with tracking link transitions</strong> - Begin by switching tracking links on your lowest-spend ad networks first to minimize potential attribution loss during the initial rollout.</li><li><strong>Maintain dual SDK coverage</strong> - Keep your existing MMP SDK active for a minimum of 2 weeks post-release to ensure continuous data collection from users who haven&#39;t yet updated to the latest app version containing the Branch SDK.</li><li><strong>Implement a forced app update</strong> - Consider requiring users to update to the latest version to ensure your entire user base transitions to Branch SDK rather than remaining on your legacy MMP solution.</li><li><strong>Migrate all optimization events</strong> - Ensure that every event currently sent to ad networks for campaign optimization is properly configured to flow through the Branch SDK.</li><li><strong>Phase your implementation approach</strong> - Begin by replicating your current MMP configuration exactly within Branch, then gradually expand functionality and explore additional features once the baseline setup is stable.</li></ul><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>To follow the steps in this guide, you must <a href="https://branchdocs.app.link/e/migration-dashboard" target="_blank" rel="noreferrer">sign up</a> for the Branch Growth Platform. Some features are included in the Branch Growth Platform, while others require a specific package. Please visit our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing</a> page or <a href="https://branchdocs.app.link/e/migration-sales" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>You must add a payment method to your account within 30 days of creating it. Learn more on our <a href="./how-billing-works.html">billing page</a>.</p></div><h3 id="audit-current-mmp" tabindex="-1">Audit current MMP <a class="header-anchor" href="#audit-current-mmp" aria-label="Permalink to &quot;Audit current MMP&quot;">​</a></h3><p>Before you start migrating to Branch, you’ll need to understand your current MMP setup and the features that you use. We recommend creating an inventory of this so you know what needs to migrate to Branch.</p><p>You can also think about whether you want to add additional functionality to your setup by broadening the scope of features you use with Branch.</p><p>Alternatively, you may want to do some cleanup and maintenance during the migration to get rid of things like unused links or old events.</p><p><strong>After you complete this step</strong>, you’ll be ready to start migrating to Branch.</p><details><summary>Expand to view tasks</summary><h4 id="organic-channels" tabindex="-1">Organic channels <a class="header-anchor" href="#organic-channels" aria-label="Permalink to &quot;Organic channels&quot;">​</a></h4><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th></tr></thead><tbody><tr><td>Inventory owned links</td><td>Marketing Team</td><td>For every link you are using with your existing MMP, you will need to replace that with a Branch Link. This means determining where all the links you are using today in your organic/owned channels live. If you currently use an API to generate your links, you can continue to do so using the <a href="https://help.branch.io/apidocs/deep-linking-api" target="_blank" rel="noreferrer">Branch Deep Linking API</a>.</td></tr><tr><td>Domain</td><td>Marketing Team</td><td>Note what your current domain is and whether it’s: 1. a custom domain you own, or 2. a domain provided by default, owned by your current MMP For example, if the domain is branded and ends in <code>.com</code>, it is likely a custom domain. Decide whether you want to use this same custom domain with Branch. By default, Branch will assign you an <code>app.link</code> domain.</td></tr></tbody></table><h4 id="paid-channels" tabindex="-1">Paid channels <a class="header-anchor" href="#paid-channels" aria-label="Permalink to &quot;Paid channels&quot;">​</a></h4><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th></tr></thead><tbody><tr><td>Audit ad partners</td><td>Marketing Team</td><td>Create a list of the ad partners that you are using with your current MMP. First, verify whether these <a href="./ad-partners-list.html">ad partners are already listed</a> as integrations in Branch. To include an ad partner that isn&#39;t on the list, refer to our guide on how to <a href="./adding-custom-partners.html">add custom ad partner integrations.</a></td></tr><tr><td>Assess SKAN</td><td>Marketing Team</td><td>Confirm whether your team uses SKAN with your current MMP, and whether this setup was implemented in-house.</td></tr><tr><td>Inventory ad links</td><td>Marketing Team</td><td>For every link you are using with your existing MMP, you will need to replace that with a Branch Ad Link. This means determining where all the links you are using today in your paid channels live.</td></tr><tr><td>Audit events used for optimization</td><td>Marketing Team</td><td>Create an inventory of the events you currently use to optimize paid media spend. Your Development Team will need to track these through the Branch SDK, so they get forwarded to ad partners.</td></tr></tbody></table><h4 id="data" tabindex="-1">Data <a class="header-anchor" href="#data" aria-label="Permalink to &quot;Data&quot;">​</a></h4><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th></tr></thead><tbody><tr><td>Account for data exports</td><td>Data Team</td><td>Determine the ways in which you are exporting data out of your current MMP, and decide whether you would like to replicate the same setup in Branch. If you use an API to export data today, you can continue to do so using one of <a href="https://www.branch.io/resources/blog/which-branch-data-export-solution-should-i-use-2/" target="_blank" rel="noreferrer">Branch&#39;s Export APIs</a>.</td></tr><tr><td>Plan event tracking</td><td>Marketing Team</td><td>Create a list of all the events your current setup tracks. Decide whether you would like to continue tracking the same events with Branch.</td></tr><tr><td>Consider importing existing users</td><td>Data Team</td><td>If your MMP allows you to export a list of your existing user IDs, you’ll need to think about whether you want to import this list into Branch.</td></tr></tbody></table></details><h2 id="migrate-to-branch" tabindex="-1">Migrate to Branch <a class="header-anchor" href="#migrate-to-branch" aria-label="Permalink to &quot;Migrate to Branch&quot;">​</a></h2><p>Follow these steps to transition from your current MMP to Branch while preserving your attribution data and minimizing disruption to your marketing campaigns.</p><h3 id="step-1-import-historical-data-optional" tabindex="-1">Step 1: Import historical data (optional) <a class="header-anchor" href="#step-1-import-historical-data-optional" aria-label="Permalink to &quot;Step 1: Import historical data (optional)&quot;">​</a></h3><p>You have two options for this step:</p><ul><li><strong>Skip if</strong>: You&#39;re comfortable starting fresh with new data collection.</li><li><strong>Complete if</strong>: You want to preserve historical attribution data and user profiles. Once you have your data in the required format, the Branch team will import this data into our system. We recommend importing a maximum of six months of data.</li></ul><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>If you install the Branch SDK without completing this step first, all existing users will appear as new installs in your data.</p></div><p><strong>After you complete this step</strong>, you’ll have historical data in Branch that you can start to gain new insights into.</p><details><summary>Expand to view tasks</summary><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th><th><strong>Time estimate*</strong></th></tr></thead><tbody><tr><td>Export data out of current MMP</td><td>Data Team</td><td>Export device IDs and timestamps from current MMP. Ensure you have IDFA/IDFV for iOS devices and GAID/Android ID for Android devices</td><td>1 day</td></tr><tr><td>Format data in Branch-compatible format</td><td>Data Team</td><td>Format data into JSON line text format with required fields (timestamp, app_id, device IDs). Reference our <a href="https://help.branch.io/developers-hub/docs/importing-historical-user-data#import-file-format" target="_blank" rel="noreferrer">importing guide</a> for exact format requirements and optional attribution fields. Please note that you will also need your Branch App ID, which you can find in the <a href="https://dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Profile tab</a> of the <strong>Account Settings</strong> page.</td><td>2 days</td></tr><tr><td>Share your data files with the Branch team</td><td>Data Team</td><td>Once you have submitted the files to Branch in the right format, the Branch team will ingest this data into our database.</td><td>2 days</td></tr></tbody></table></details><h3 id="step-2-configure-branch-and-integrate-sdk" tabindex="-1">Step 2: Configure Branch and integrate SDK <a class="header-anchor" href="#step-2-configure-branch-and-integrate-sdk" aria-label="Permalink to &quot;Step 2: Configure Branch and integrate SDK&quot;">​</a></h3><p>Set up your Branch account, integrate the Branch SDK into your mobile app, and release the updated version.</p><p><strong>After you complete this step</strong>, Branch will start actively tracking attribution data for your app, and you&#39;ll be ready to begin transitioning your marketing campaigns to use Branch Links.</p><details><summary>Expand to view tasks</summary><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th><th><strong>Time estimate*</strong></th></tr></thead><tbody><tr><td>Set up Branch Dashboard</td><td>Marketing Team</td><td>Configure important fields within the Branch Dashboard, such as link domain and global attribution window settings. Visit our <a href="https://help.branch.io/docs/onboarding-guide#step-1-set-up-branch-dashboard" target="_blank" rel="noreferrer">general onboarding guide</a> for more details.</td><td>1 day</td></tr><tr><td>Set up Branch SDK, track Branch Events, and validate setup</td><td>Mobile Development Team</td><td>Integrate the Branch SDK into your app and use it to start tracking Branch Events. Visit our <a href="https://help.branch.io/docs/onboarding-guide#step-2-set-up-branch-mobile-sdks" target="_blank" rel="noreferrer">general onboarding guide</a> for more details.</td><td>8 days</td></tr><tr><td>Release your app</td><td>Mobile Development Team</td><td><strong>Important</strong>: If you choose to <a href="./migration-guide.html#step-1-import-historical-data-optional">import historical data</a>, please ensure that the import is complete before you release the app. Branch recommends releasing your app with both your existing MMP and Branch enabled for a short period of time (at least 2 weeks). This will prevent any gaps in your data as users migrate onto the new version of your app. After that, you can remove your existing MMP from future app updates.</td><td>1 day</td></tr></tbody></table><p>If you are planning to use the same custom domain on Branch as your previous MMP, you will need to CNAME the domain and migrate the links. Migration of the domain can lead to a short down time when transitioning to Branch.</p></details><h3 id="step-3-migrate-owned-links" tabindex="-1">Step 3: Migrate owned links <a class="header-anchor" href="#step-3-migrate-owned-links" aria-label="Permalink to &quot;Step 3: Migrate owned links&quot;">​</a></h3><p>Owned media refers to attribution links you use in content sharing, email, SMS, referrals, social media posts, blogs, and push notifications. Use Branch Short Links (App Links or Web Links) for these channels.</p><p><strong>After you complete this step</strong>, all your owned media channels will be using Branch Links for attribution tracking.</p><details><summary>Expand to view tasks</summary><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th><th><strong>Time estimate*</strong></th></tr></thead><tbody><tr><td>Re-create owned links in Branch</td><td>Marketing Team, Development Team</td><td>Using your existing owned links as reference, re-create your links with Branch. You have several options for how to create links: in the Dashboard, with one of our APIs, or using the SDK. Learn more in our <a href="./create-app-links.html">App Link</a> and <a href="./create-web-links.html">Web Link</a> guides.</td><td>2-5 days, depending on how many links you need to re-create</td></tr><tr><td>Replace old owned links</td><td>Marketing Team</td><td>Replace your existing owned links from your old MMP with your new Branch Links.</td><td>1-3 days, depending on how many links you need to replace</td></tr></tbody></table></details><h3 id="step-4-set-up-ad-partner-configurations" tabindex="-1">Step 4: Set up ad partner configurations <a class="header-anchor" href="#step-4-set-up-ad-partner-configurations" aria-label="Permalink to &quot;Step 4: Set up ad partner configurations&quot;">​</a></h3><p>Configure self-attributing network (SAN) ad partners like Google and Facebook, set up other non-SAN ad partners, and gradually replace your existing ad campaign links with Branch Ad Links.</p><p><strong>After you complete this step</strong>, all your paid advertising channels will be integrated with Branch, giving you unified attribution measurement across both owned and paid user acquisition efforts.</p><details><summary>Expand to view tasks</summary><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th><th><strong>Time estimate*</strong></th></tr></thead><tbody><tr><td>Integrate SAN partners in Branch</td><td>Marketing Team</td><td>Enable all relevant SAN partners in the Branch Dashboard, and map your Branch Events to the ad partner events. Only Apple Ads and Google support connecting multiple MMPs. For all other partners, you will need to disable the ad partner from your previous MMP before you enable them in Branch. For more information on individual SAN partners, visit our guides: - <a href="./google-ads.html">Google</a> - <a href="./facebook-ads-index.html">Facebook/Meta</a> - <a href="./apple-ads-index.html">Apple Ads</a> - <a href="./snap.html">Snap</a> - <a href="./twitter-ads.html">Twitter</a> - <a href="./tiktok-for-business.html">TikTok For Business</a></td><td>15 minutes per ad partner</td></tr><tr><td>Replace SAN links</td><td>Marketing Team</td><td>In your SAN campaigns, replace each of your existing MMP ad links with a Branch Ad Link. Learn more in our <a href="./ad-links.html">Ad Link</a> guide.</td><td>1-2 days, depending on how many links you need to re-create and replace</td></tr><tr><td>Integrate non-SAN partners in Branch</td><td>Marketing Team</td><td>Enable all relevant non-SAN partners in the Branch Dashboard, and validate the Postbacks to ensure the right events are sent to the ad partner. Start with low-spend networks to mitigate the risk of lost attribution. For more details, visit our <a href="./ad-partner-integration-guide.html">Ad Partner Integration</a> guide.</td><td>15 minutes per ad partner</td></tr><tr><td>Replace non-SAN links</td><td>Marketing Team</td><td>In your non-SAN campaigns, replace each of your existing MMP ad links with a Branch Ad Link. Learn more in our <a href="./ad-links.html">Ad Link</a> guide.</td><td>1-2 days, depending on how many links you need to re-create and replace</td></tr><tr><td>Use SKAN with Branch</td><td>Marketing Team, Development Team</td><td>SKAN postbacks can be supported only by a single MMP. If your existing MMP is already sending SKAN postbacks to Apple, you will need to wait until the legacy MMP is fully disabled to start using SKAN with Branch. To start using SKAN with Branch: 1. Ensure <a href="https://developer.apple.com/documentation/storekit" target="_blank" rel="noreferrer">StoreKit</a> is enabled on the app (to be done by developer) 2. Test SKAN campaign with ad partners: - <a href="./google-skadnetwork.html">Google Ads</a> - <a href="./tiktok-skadnetwork.html">TikTok</a> - <a href="./facebook-skadnetwork.html">Facebook</a></td><td>5 hours</td></tr></tbody></table></details><h3 id="step-5-set-up-data-exports" tabindex="-1">Step 5: Set up data exports <a class="header-anchor" href="#step-5-set-up-data-exports" aria-label="Permalink to &quot;Step 5: Set up data exports&quot;">​</a></h3><p>Configure integrations to send Branch data to supported data partners. This ensures your downstream systems continue to receive the attribution data they need without interruption.</p><p>To determine which Branch data export(s) best fit your use cases, check out this <a href="https://www.branch.io/resources/blog/which-branch-data-export-solution-should-i-use-2/" target="_blank" rel="noreferrer">blog post</a>.</p><p><strong>After you complete this step</strong>, your migration to Branch will be functionally complete. All your marketing channels will be tracked through Branch, and your data infrastructure will be receiving Branch attribution data for analysis and reporting.</p><details><summary>Expand to view tasks</summary><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th><th><strong>Time estimate*</strong></th></tr></thead><tbody><tr><td>Integrate Branch with data partners</td><td>Data Team</td><td>If you’d like to send Branch data to a supported data partner, you can configure that integration in the Branch Dashboard. Visit our general <a href="./data-integration-implementation-guide.html">Data Integration Implementation</a> guide for more details.</td><td>15 minutes per partner</td></tr><tr><td>Pass partner-specific metadata to Branch SDK</td><td>Data Team</td><td>To pass Branch Event data to your data partner, you will first need to pass partner-specific metadata to the Branch SDK. Refer to our list of <a href="./data-integration-partners.html">Data Integration Partners</a> for detailed information regarding the metadata that must be sent for each data partner.</td><td>1 hour</td></tr><tr><td>Export Branch data using APIs</td><td>Data Team</td><td>You can export Branch data either at the aggregate-level or the log-level based on your requirements. Log-level: - <a href="https://help.branch.io/apidocs/daily-exports-api" target="_blank" rel="noreferrer">Daily Export API</a> - <a href="https://help.branch.io/apidocs/custom-exports-api" target="_blank" rel="noreferrer">Custom Export API</a> - <a href="https://help.branch.io/apidocs/scheduled-log-exports-api" target="_blank" rel="noreferrer">Scheduled Log Exports API</a> Aggregate-level: - <a href="http://help.branch.io/apidocs/aggregate-api" target="_blank" rel="noreferrer">Aggregate API</a> - <a href="https://help.branch.io/apidocs/query-api" target="_blank" rel="noreferrer">Query API</a> - <a href="https://help.branch.io/apidocs/cross-events-export-api" target="_blank" rel="noreferrer">Cross-Events Export API</a></td><td>3 hours</td></tr><tr><td>Test and validate your setup</td><td>Data Team</td><td>For data partner integrations, you can reference the <a href="https://dashboard.branch.io/overview/webhooks" target="_blank" rel="noreferrer">Liveview Webhook Records</a> tab to monitor the data being passed to your data partners in real time. Also make sure to verify that any Branch APIs you are utilizing are providing the expected outputs.</td><td>1 hour</td></tr></tbody></table></details><h3 id="step-6-remove-existing-mmp-sdk" tabindex="-1">Step 6: Remove existing MMP SDK <a class="header-anchor" href="#step-6-remove-existing-mmp-sdk" aria-label="Permalink to &quot;Step 6: Remove existing MMP SDK&quot;">​</a></h3><p>Once a few weeks have passed after releasing your app with both your existing MMP SDK and the Branch SDK, remove the existing MMP SDK.</p><p><strong>After you complete this step</strong>, Branch will be completely integrated as your new MMP and your app will no longer be dependent on your legacy MMP.</p><details><summary>Expand to view tasks</summary><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th></tr></thead><tbody><tr><td>Review the app code and note down all references to the existing MMP SDK code</td><td>Development Team</td><td>Identify any areas in the code where the existing MMP SDK is being used or there are references to it. Be sure to note any libraries that the existing MMP SDK imports by default, in case your app has dependencies on those.</td></tr><tr><td>Remove the existing MMP SDK code and any references to it</td><td>Development Team</td><td>Remove the legacy MMP SDK from the code, along with any references to it. If there were any dependencies that it imported by default which your app depends on, include those individually.</td></tr><tr><td>Test that the app functions as expected</td><td>Development Team / QA Team</td><td>Perform regression testing to ensure that the removal of the legacy MMP SDK didn’t cause any bugs or cause any crashes when going through various flows your users would perform.</td></tr><tr><td>Release the app with the updates</td><td>Development Team</td><td>Submit the app without the legacy MMP SDK to the app store.</td></tr></tbody></table></details><h2 id="additional-support" tabindex="-1">Additional support <a class="header-anchor" href="#additional-support" aria-label="Permalink to &quot;Additional support&quot;">​</a></h2><p>Branch offers several ways to connect with expert guidance as you learn how to use all the powerful features of the Branch Growth Platform.</p><h3 id="live-trainings" tabindex="-1">Live trainings <a class="header-anchor" href="#live-trainings" aria-label="Permalink to &quot;Live trainings&quot;">​</a></h3><p>For continued learning, <a href="https://branchu.app.link/e/XvE0493DFVb" target="_blank" rel="noreferrer">Branch University</a> offers live, expert-led <a href="https://monster-factory-web.app.link/e/universitylive" target="_blank" rel="noreferrer">training sessions</a> designed to help you master our products, sharpen your skills, and gain hands-on experience. These sessions provide an opportunity to ask questions directly to our trainers, ensuring you get the most out of the Branch Growth Platform.</p><h3 id="professional-services" tabindex="-1">Professional Services <a class="header-anchor" href="#professional-services" aria-label="Permalink to &quot;Professional Services&quot;">​</a></h3><p>For deeper technical support, QA testing, or custom solutions, our Professional Services team is here to help. We offer dedicated workshops to better understand your goals, assist with setup, and provide guidance through go-live and beyond.</p><p>To learn more, please reach out to your Branch point of contact or <a href="https://branchdocs.app.link/e/migration-sales" target="_blank" rel="noreferrer">contact our Sales team</a> to request scoping.</p><p>*<em>The time estimates provided for each task are approximate and intended as general guidance. Actual completion times may vary depending on factors such as your team’s prior experience with Branch and the complexity of your existing app logic.</em></p>',51)])])}const g=e(o,[["render",i]]);export{c as __pageData,g as default};
